#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int solve(vector<int>& nums) {
        int n = nums.size();
        if (n <= 1) return 0;
        int jumps = 0;
        int current_end = 0;
        int farthest = 0;
        for (int i = 0; i < n - 1; ++i) {
            farthest = max(farthest, i + nums[i]);
            if (i == current_end) {
                ++jumps;
                current_end = farthest;
                if (current_end >= n - 1) break;
                if (current_end <= i) return -1; // cannot move further
            }
        }
        return (current_end >= n - 1) ? jumps : -1;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; ++i) cin >> nums[i];
    Solution sol;
    int ans = sol.solve(nums);
    cout << ans << "\n";
    return 0;
}
